site_id = #{siteId}, order_id = #{orderId}, discnt_type_cd = #{discntTypeCd}, coupon_id = #{couponId}, coupon_issue_id = #{couponIssueId}, discnt_rate = #{discntRate}, discnt_amt = #{discntAmt}, base_item_amt = #{baseItemAmt}, restore_yn = #{restoreYn}, restore_amt = #{restoreAmt}, restore_date = #{restoreDate},
WHERE order_discnt_id = #{orderDiscntId}
